-- =============================================================================
-- Migration: Seed shopify_stores + realistic test orders for time series
-- =============================================================================
-- WHY: platform.shopify_stores has 0 rows (no timezone/currency metadata) and
-- airbyte_raw.orders has 0 rows (test Shopify store has no orders placed).
-- Without orders, the entire revenue pipeline produces nothing:
--   stg_shopify_orders → canonical.orders → marts.mart_revenue_metrics → 0 rows
--
-- This migration seeds:
--   1. A shopify_stores record for the connected test store
--   2. 60 realistic test orders spanning 90 days for time series reporting
--
-- IDEMPOTENT: Uses ON CONFLICT DO NOTHING for the store record.
-- Orders use unique IDs (900001-900060) unlikely to collide with real data.
-- =============================================================================

-- 1. Seed shopify_stores
INSERT INTO platform.shopify_stores (id, tenant_id, shop_domain, timezone, currency, country, status)
VALUES (
    'store-' || md5('test-store-markinsight'),
    '7b9aad14-bb5c-4659-a23d-a5deecc8c52a',
    'test-1111111111111111111111111111111111711111111111129799',
    'America/New_York',
    'USD',
    'US',
    'active'
)
ON CONFLICT (id) DO NOTHING;

-- 2. Seed 60 test orders into airbyte_raw.orders (V2 typed columns)
-- Spread across 90 days with varied amounts and statuses.
-- shop_url MUST match the tenant_airbyte_connections.configuration->>'shop_domain'
-- so the staging model's tenant join succeeds.

INSERT INTO airbyte_raw.orders (
    _airbyte_raw_id, _airbyte_extracted_at, _airbyte_meta, _airbyte_generation_id,
    id, name, email, shop_url, created_at, updated_at,
    financial_status, fulfillment_status,
    total_price, subtotal_price, total_tax, currency,
    order_number, confirmed, taxes_included,
    total_discounts, total_line_items_price, total_price_usd,
    current_total_price, current_subtotal_price, current_total_tax,
    current_total_discounts, total_outstanding, total_tip_received,
    buyer_accepts_marketing, test,
    total_shipping_price_set, customer, refunds, line_items, tax_lines,
    shipping_lines, discount_codes, note_attributes, fulfillments,
    payment_gateway_names, discount_applications, discount_allocations
)
